package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.stubbing.Answer;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormatWithNormalValues() {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormatWithNullValue() {
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        String result = format.format("a", null, "c");
        assertEquals("a,NULL,c", result);
    }

    @Test
    void testFormatWithEmptyValues() {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormatWithValuesContainingComma() {
        String result = csvFormat.format("a,b", "c");
        assertEquals("\"a,b\",c", result);
    }

    @Test
    void testFormatThrowsIllegalStateExceptionOnIOException() throws IOException {
        // Mock CSVPrinter constructor using Mockito 3 and reflection workaround
        CSVFormat format = spy(CSVFormat.DEFAULT);

        // Use reflection to replace CSVPrinter with a mock that throws IOException on printRecord
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        // Disambiguate printRecord call by casting argument to Object[]
        doThrow(new IOException("IO error")).when(mockPrinter).printRecord((Object[]) any());

        // Replace the CSVFormat#format method's CSVPrinter creation with our mock via spy and doAnswer
        doAnswer((Answer<String>) invocation -> {
            Object[] args = invocation.getArguments();
            Object[] values = (Object[]) args[0];

            StringWriter out = new StringWriter();
            try (CSVPrinter printer = mockPrinter) {
                printer.printRecord(values);
                return out.toString().trim();
            } catch (IOException e) {
                throw new IllegalStateException(e);
            }
        }).when(format).format(any());

        IllegalStateException exception = assertThrows(IllegalStateException.class, () -> {
            format.format("a", "b");
        });
        assertTrue(exception.getCause() instanceof IOException);
        assertEquals("IO error", exception.getCause().getMessage());
    }

}
